import{_ as t,o as e,c as n,ag as r}from"./chunks/framework.Dr9kcJF8.js";const h=JSON.parse('{"title":"中频quant：故事与数据齐飞","description":"","frontmatter":{"year":25,"type":"job","degree":"ms","region":"us","school":"sds","date":"2026-04-23T00:00:00.000Z"},"headers":[],"relativePath":"post/25fall-quant.md","filePath":"post/25fall-quant.md"}'),u={name:"post/25fall-quant.md"};function l(o,a,i,d,s,q){return e(),n("div",null,[...a[0]||(a[0]=[r('<h1 id="中频quant-故事与数据齐飞" tabindex="-1">中频quant：故事与数据齐飞 <a class="header-anchor" href="#中频quant-故事与数据齐飞" aria-label="Permalink to &quot;中频quant：故事与数据齐飞&quot;">​</a></h1><h2 id="quant行业生态" tabindex="-1">quant行业生态 <a class="header-anchor" href="#quant行业生态" aria-label="Permalink to &quot;quant行业生态&quot;">​</a></h2><ul><li>高频quant：代表公司有HRT, Citadel Securities, Jump Trading，也是大家常说的Prop Trading或者Market Maker。这类公司解决的是数学问题，怎么在毫秒之内调整订单位置来控制仓位与风险。面试题会以做题编程为主，考察基础的数理能力。</li><li>中频quant：代表公司有Millennium, Point72, Citadel, 也是大家常说的Hedge Fund。这类公司解决的是经济学问题（alpha），怎么在市场中用合适的投资组合实现预测出的alpha。面试题会以分享过往经历为主，考察逻辑和沟通能力</li><li>低频quant：类似于Vanguard这样的Asset Management。不太熟悉。</li></ul><p>当然这个分类不是绝对的，Prop Trading也会有中频策略，Hedge Fund也在尝试搭建自己的高频策略与执行系统。但作为一个junior quant求职者，走进全职就业市场前（也就是最后一次实习前）的第一步就要找到自己的edge，是擅长推导公式并写出高效率代码还是解释现象并找出alpha。</p><h2 id="完全依赖公开信息规划个人发展-泯然众人" tabindex="-1">完全依赖公开信息规划个人发展 = 泯然众人 <a class="header-anchor" href="#完全依赖公开信息规划个人发展-泯然众人" aria-label="Permalink to &quot;完全依赖公开信息规划个人发展 = 泯然众人&quot;">​</a></h2><p>对quant行业好奇的人常会寻求公开的资源学习，这无可厚非，但quant这个行业是典型的优胜劣汰的行业。如果一位quant在自己的领域做不到中位数，那就很难在面试中说服面试官，那求职必然艰难；如果一位quant可以在自己的领域做到90%的upper quantile，并且这个技能被PM所需要，那求职将一帆风顺。所以想成为一位优秀的quant，首先要在一个具体的领域成为最优秀的一批人，这个领域可以是贝叶斯分析，也可以是Deep Learning，还可以是金融基本面建模，甚至可以是和quant无关的市场营销、社会学和新闻学，但唯独不能只是公开信息里流传的&quot;quant&quot;。</p><h2 id="控制好个人职业风险" tabindex="-1">控制好个人职业风险 <a class="header-anchor" href="#控制好个人职业风险" aria-label="Permalink to &quot;控制好个人职业风险&quot;">​</a></h2><p>竞业协议对于应届生来说还比较远，我们可以聊聊实习时就会遇到的职业风险。常见坑的比如：阴阳合同（你实际工作公司和合同上的公司不一样），对你不利的离职原因，完全拒绝配合背景调查/提交推荐信。这些是入职公司前就要考察清楚的，一般越有名气的公司越正规，小作坊容易出现各种各样的后续问题。一旦你发现这段实习有可能影响背调，一定要坚决地舍弃掉这段经历，无论你是正在实习还是已经结束实习。外资背调一般是7年过往雇佣经历，不要让一家抽象的公司影响你的后续入职。</p><p>除了合规方面的，实习生也要会考察mentor的能力。一般来说实习开始的第一周，可以认为是你对公司和组里面成员的为期一周的superday，如果你发现组里面一些研究极度不合理或者完全依赖复现卖方研报获得&quot;alpha&quot;，那就只有一个词送给你：</p><div align="center" style="font-size:30px;font-weight:bold;"> Run! </div>',10)])])}const c=t(u,[["render",l]]);export{h as __pageData,c as default};
